const install=async url=>{const path=url.substr(0,url.lastIndexOf("/")),blamElements=[...document.querySelectorAll(":not(:defined)")].filter(elem=>elem.nodeName.includes("-BLAM")),uniqueNames=[...new Set(blamElements.map(elem=>elem.nodeName.toLowerCase()))];for(const name of uniqueNames)await import(`${path}/elements/${name.split("-")[0]}.js`);let ready=new CustomEvent("blamready");window.dispatchEvent(ready)};export{install};